Setup

library(causatr)

compare_row &lt;- function(label, result, name, ref_name,
                        ref_est, ref_se, level = 0.95) {
  con &lt;- result$contrasts
  est &lt;- result$estimates
  if (name %in% con$comparison) {
    row &lt;- con[con$comparison == name, ]
  } else if (name %in% est$intervention) {
    row &lt;- est[est$intervention == name, ]
  } else {
    stop(
      "name '", name,
      "' not found in result$contrasts$comparison or result$estimates$intervention"
    )
  }
  stopifnot(
    length(ref_est) == 1L && is.finite(ref_est),
    length(ref_se) == 1L && is.finite(ref_se)
  )
  z &lt;- stats::qnorm(1 - (1 - level) / 2)
  data.table::data.table(
    quantity = label,
    source = c("causatr", ref_name),
    estimate = c(row$estimate, ref_est),
    se = c(row$se, ref_se),
    ci_lower = c(row$ci_lower, ref_est - z * ref_se),
    ci_upper = c(row$ci_upper, ref_est + z * ref_se)
  )
}

compare_row() pulls an estimate from a causatr_result (either an intervention mean or a contrast by name) and pairs it with a reference estimate + SE under a normal-approximation CI. The output is a two-row data.table you can print verbatim.
We use two small simulated DGPs for reproducibility. NHEFS would work too, but inline simulation keeps the vignette self-contained and cheap to render.

simulate_point &lt;- function(n = 2000, seed = 1L, binary_outcome = FALSE) {
  set.seed(seed)
  L &lt;- stats::rnorm(n)
  A &lt;- stats::rbinom(n, 1L, stats::plogis(0.4 * L))
  if (binary_outcome) {
    Y &lt;- stats::rbinom(n, 1L, stats::plogis(-0.5 + 0.8 * A + 0.3 * L))
  } else {
    Y &lt;- 1 + 2 * A + 0.5 * L + stats::rnorm(n, sd = 0.8)
  }
  data.frame(L = L, A = A, Y = Y)
}

simulate_longitudinal &lt;- function(n = 500L, K = 3L, seed = 2L) {
  set.seed(seed)
  L &lt;- matrix(0, n, K)
  A &lt;- matrix(0L, n, K)
  for (k in seq_len(K)) {
    L[, k] &lt;- stats::rnorm(n) +
      if (k == 1L) 0 else 0.3 * A[, k - 1L]
    A[, k] &lt;- stats::rbinom(n, 1L, stats::plogis(0.3 * L[, k]))
  }
  Y &lt;- stats::rbinom(n, 1L, stats::plogis(-1 + 0.4 * rowSums(A) + 0.2 * L[, K]))
  wide &lt;- data.table::data.table(id = seq_len(n))
  for (k in seq_len(K)) {
    wide[[paste0("L", k)]] &lt;- L[, k]
    wide[[paste0("A", k)]] &lt;- A[, k]
  }
  wide$Y &lt;- Y
  wide[]
}

simulate_longitudinal_continuous &lt;- function(n = 400L, K = 2L, seed = 3L) {
  set.seed(seed)
  L &lt;- matrix(0, n, K)
  A &lt;- matrix(0, n, K)
  for (k in seq_len(K)) {
    L[, k] &lt;- stats::rnorm(n) +
      if (k == 1L) 0 else 0.2 * A[, k - 1L]
    A[, k] &lt;- stats::rnorm(n, mean = 0.3 * L[, k], sd = 1)
  }
  Y &lt;- 1 + rowSums(A) + 0.3 * L[, K] + stats::rnorm(n, sd = 0.5)
  wide &lt;- data.table::data.table(id = seq_len(n))
  for (k in seq_len(K)) {
    wide[[paste0("L", k)]] &lt;- L[, k]
    wide[[paste0("A", k)]] &lt;- A[, k]
  }
  wide$Y &lt;- Y
  wide[]
}
